button.description:
# component.button

## Description
Composant de bouton réutilisable supportant 3 tailles (sm, md, lg) avec gestion des états (default, hover, focus, disabled). Intègre les tokens de design pour l'espacement, la typographie et les interactions.

## Do & Don't
✅ **Do**
- Utiliser les sizes sm/md/lg selon le contexte UX (petit texte pour sm, actions principales pour lg)

❌ **Don't**
- Combiner plusieurs variantes de couleur et taille sans test d'accessibilité

## 💻 Code interactif (Live Editor)

```jsx
import React from 'react';

const Button = ({ 
  size = 'md', 
  variant = 'primary',
  disabled = false,
  children,
  ...props 
}) => {
  const sizeConfig = {
    sm: {
      paddingX: 'var(--spacing-sm)',
      paddingY: 'var(--spacing-xs)',
      fontSize: 'var(--font-size-sm)',
      minHeight: '32px',
      gap: 'var(--spacing-xs)',
      iconSize: '16px'
    },
    md: {
      paddingX: 'var(--spacing-md)',
      paddingY: 'var(--spacing-sm)',
      fontSize: 'var(--font-size-sm)',
      minHeight: '40px',
      gap: 'var(--spacing-sm)',
      iconSize: '20px'
    },
    lg: {
      paddingX: 'var(--spacing-lg)',
      paddingY: 'var(--spacing-sm)',
      fontSize: 'var(--font-size-md)',
      minHeight: '48px',
      gap: 'var(--spacing-sm)',
      iconSize: '24px'
    }
  };

  const baseStyle = {
    fontFamily: 'var(--font-family-default)',
    fontWeight: 'var(--font-weight-semibold)',
    lineHeight: 'var(--font-lineHeight-normal)',
    borderRadius: 'var(--radius-md)',
    border: `var(--borderWidth-default) solid transparent`,
    cursor: disabled ? 'not-allowed' : 'pointer',
    transition: 'var(--transition)',
    display: 'inline-flex',
    alignItems: 'center',
    justifyContent: 'center',
    opacity: disabled ? 0.5 : 1,
    ...sizeConfig[size]
  };

  const variantStyles = {
    primary: {
      backgroundColor: 'var(--semantic-color-action-primary-bg-default)',
      color: 'var(--semantic-color-action-primary-text-default)',
    },
    secondary: {
      backgroundColor: 'var(--semantic-color-action-secondary-bg-default)',
      color: 'var(--semantic-color-action-secondary-text-default)',
      borderColor: 'var(--semantic-color-action-secondary-border-default)'
    },
    tertiary: {
      backgroundColor: 'transparent',
      color: 'var(--semantic-color-action-tertiary-text-default)'
    }
  };

  const buttonStyle = { ...baseStyle, ...variantStyles[variant] };

  return (
    <button 
      style={buttonStyle} 
      disabled={disabled}
      {...props}
    >
      {children}
    </button>
  );
};

export default function ButtonDemo() {
  return (
    <div style={{ display: 'flex', gap: '16px', alignItems: 'center', padding: '24px' }}>
      <Button size="sm" variant="primary">Small</Button>
      <Button size="md" variant="primary">Medium</Button>
      <Button size="lg" variant="primary">Large</Button>
    </div>
  );
}
```

input.description:
# component.input

## Description
Composant Input réutilisable qui gère les états (défaut, hover, focus, erreur, désactivé) et les tailles (sm, md, lg) via tokens de design. Il offre une expérience d'entrée de texte cohérente et accessible avec gestion des attributs HTML natifs.

## Do & Don't
✅ **Do**
- Utiliser les props `size` ("sm" | "md" | "lg"), `disabled`, `error`, et `placeholder` pour adapter le comportement du champ
- Chaîner `ref` pour accéder directement à l'élément DOM natif si besoin

❌ **Don't**
- Passer des styles inline custom qui contredisent les tokens du design system
- Oublier d'activer le prop `error` lors d'une validation échouée

## 💻 Code interactif (Live Editor)

```jsx
import React, { useState } from 'react';

const Input = React.forwardRef(
  (
    {
      size = 'md',
      disabled = false,
      error = false,
      placeholder = 'Entrez du texte...',
      value,
      onChange,
      type = 'text',
      ...props
    },
    ref
  ) => {
    const [isFocused, setIsFocused] = useState(false);

    // Tokens appliqués via variables CSS
    const sizeConfig = {
      sm: {
        paddingX: 'var(--token-spacing-sm)',
        paddingY: 'var(--token-spacing-xs)',
        fontSize: 'var(--token-font-size-sm)',
        minHeight: '32px',
      },
      md: {
        paddingX: 'var(--token-spacing-sm)',
        paddingY: 'var(--token-spacing-sm)',
        fontSize: 'var(--token-font-size-md)',
        minHeight: '40px',
      },
      lg: {
        paddingX: 'var(--token-spacing-md)',
        paddingY: 'var(--token-spacing-sm)',
        fontSize: 'var(--token-font-size-lg)',
        minHeight: '48px',
      },
    };

    const inputStyle = {
      ...sizeConfig[size],
      backgroundColor: disabled
        ? 'var(--token-color-bg-disabled)'
        : 'var(--token-color-bg-default)',
      color: disabled
        ? 'var(--token-color-text-disabled)'
        : 'var(--token-color-text-primary)',
      borderWidth: 'var(--token-borderWidth-default)',
      borderStyle: 'solid',
      borderColor: error
        ? 'var(--token-color-border-error)'
        : isFocused
        ? 'var(--token-color-border-focus)'
        : disabled
        ? 'var(--token-color-border-disabled)'
        : 'var(--token-color-border-default)',
      borderRadius: 'var(--token-radius-md)',
      fontFamily: 'inherit',
      transition: 'border-color 200ms ease, background-color 200ms ease',
      cursor: disabled ? 'not-allowed' : 'text',
      outline: 'none',
      boxSizing: 'border-box',
    };

    const placeholderStyle = {
      color: 'var(--token-color-text-placeholder)',
    };

    return (
      <input
        ref={ref}
        type={type}
        value={value}
        onChange={onChange}
        disabled={disabled}
        placeholder={placeholder}
        style={inputStyle}
        onFocus={() => setIsFocused(true)}
        onBlur={() => setIsFocused(false)}
        {...props}
      />
    );
  }
);

Input.displayName = 'Input';

// ============ DÉMONSTRATION ============
export default function InputShowcase() {
  const [text, setText] = useState('');

  const containerStyle = {
    display: 'flex',
    gap: '16px',
    alignItems: 'flex-start',
    padding: '24px',
    flexWrap: 'wrap',
  };

  const wrapperStyle = {
    display: 'flex',
    flexDirection: 'column',
    gap: '8px',
  };

  const labelStyle = {
    fontSize: '12px',
    fontWeight: '600',
    color: 'var(--token-color-text-primary)',
  };

  return (
    <div style={containerStyle}>
      <div style={wrapperStyle}>
        <label style={labelStyle}>Small (sm)</label>
        <Input
          size="sm"
          placeholder="Texte petit"
          value={text}
          onChange={(e) => setText(e.target.value)}
        />
      </div>

      <div style={wrapperStyle}>
        <label style={labelStyle}>Medium (md) - Default</label>
        <Input
          size="md"
          placeholder="Texte moyen"
          value={text}
          onChange={(e) => setText(e.target.value)}
        />
      </div>

      <div style={wrapperStyle}>
        <label style={labelStyle}>Large (lg)</label>
        <Input
          size="lg"
          placeholder="Texte grand"
          value={text}
          onChange={(e) => setText(e.target.value)}
        />
      </div>

      <div style={wrapperStyle}>
        <label style={labelStyle}>Error state</label>
        <Input
          size="md"
          error
          placeholder="Erreur"
          value={text}
          onChange={(e) => setText(e.target.value)}
        />
      </div>

      <div style={wrapperStyle}>
        <label style={labelStyle}>Disabled</label>
        <Input
          size="md"
          disabled
          placeholder="Désactivé"
          value="Non modifiable"
        />
      </div>
    </div>
  );
}
```

card.description:
# component.card

## Description
Composant conteneur polyvalent qui encapsule du contenu avec padding, arrondis et ombre. Élément fondamental du Design System pour créer des zones de contenu isolées et hiérarchisées.

## Do & Don't
✅ **Do**
- Utiliser la card pour grouper du contenu sémantiquement lié (texte, images, actions)

❌ **Don't**
- Imbriquer excessivement plusieurs cards sans justification structurelle

## 💻 Code interactif (Live Editor)

```jsx
import React from 'react';

const Card = ({ 
  children, 
  padding = 'md', 
  variant = 'default',
  className = '' 
}) => {
  const paddingMap = {
    sm: 'var(--spacing-md)',
    md: 'var(--spacing-lg)',
    lg: 'var(--spacing-xl)'
  };

  const cardStyle = {
    padding: paddingMap[padding] || paddingMap.md,
    borderRadius: 'var(--radius-lg)',
    backgroundColor: 'var(--color-bg-primary)',
    border: `1px solid var(--color-border-default)`,
    boxShadow: 'var(--shadow-100)',
    boxSizing: 'border-box'
  };

  return (
    <div style={cardStyle} className={className}>
      {children}
    </div>
  );
};

export default function CardShowcase() {
  const containerStyle = {
    display: 'flex',
    gap: 'var(--spacing-lg)',
    padding: 'var(--spacing-lg)',
    flexWrap: 'wrap'
  };

  return (
    <div style={containerStyle}>
      <Card padding="sm">
        <h3>Petit padding</h3>
        <p>Contenu avec spacing réduit</p>
      </Card>

      <Card padding="md">
        <h3>Padding standard</h3>
        <p>Contenu avec spacing normal</p>
      </Card>

      <Card padding="lg">
        <h3>Grand padding</h3>
        <p>Contenu avec spacing amplifié</p>
      </Card>
    </div>
  );
}
```

badge.description:
# component.badge

## Description
Badge est un composant d'étiquetage compact destiné à signaler des statuts, des catégories ou des métriques. Il applique une typographie réduite avec un padding proportionné et une bordure arrondie pour une intégration visuelle légère.

## Do & Don't
✅ **Do**
- Utiliser le badge pour labéliser des statuts courts (< 3 mots)

❌ **Don't**
- Ne pas y placer du contenu long ou multilignes

## 💻 Code interactif (Live Editor)

```jsx
import React from 'react';

const Badge = ({ children, variant = 'default', ...props }) => {
  // Styles moteur liés aux tokens du design system
  const baseStyle = {
    paddingLeft: 'var(--spacing-sm)',
    paddingRight: 'var(--spacing-sm)',
    paddingTop: 'var(--spacing-xs)',
    paddingBottom: 'var(--spacing-xs)',
    fontSize: 'var(--font-size-xs)',
    fontWeight: 'var(--font-weight-medium)',
    borderRadius: 'var(--radius-full)',
    display: 'inline-flex',
    alignItems: 'center',
    justifyContent: 'center',
    whiteSpace: 'nowrap',
    userSelect: 'none'
  };

  const variantStyles = {
    default: {
      backgroundColor: 'var(--semantic-color-neutral-bg-secondary)',
      color: 'var(--semantic-color-neutral-fg-default)'
    },
    primary: {
      backgroundColor: 'var(--semantic-color-action-primary-bg-default)',
      color: 'var(--semantic-color-action-primary-fg-default)'
    },
    success: {
      backgroundColor: 'var(--semantic-color-feedback-success-bg-default)',
      color: 'var(--semantic-color-feedback-success-fg-default)'
    }
  };

  const mergedStyle = {
    ...baseStyle,
    ...(variantStyles[variant] || variantStyles.default)
  };

  return (
    <span style={mergedStyle} {...props}>
      {children}
    </span>
  );
};

// RENDER : Exemples de variantes
export default function BadgeShowcase() {
  const containerStyle = {
    display: 'flex',
    gap: '12px',
    alignItems: 'center',
    padding: '24px'
  };

  return (
    <div style={containerStyle}>
      <Badge variant="default">Default</Badge>
      <Badge variant="primary">Primary</Badge>
      <Badge variant="success">Active</Badge>
    </div>
  );
}
```
